import React, { useEffect, useState, useRef, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import api from '../../services/api';
import keycloak from '../../keycloak';

// ─── Icons ────────────────────────────────────────────────────────────────────

const IconUsers = ({ size = 18 }) => (
  <svg width={size} height={size} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
    <path d="M17 21v-2a4 4 0 0 0-4-4H5a4 4 0 0 0-4 4v2"/>
    <circle cx="9" cy="7" r="4"/>
    <path d="M23 21v-2a4 4 0 0 0-3-3.87"/>
    <path d="M16 3.13a4 4 0 0 1 0 7.75"/>
  </svg>
);

const IconFile = ({ size = 18 }) => (
  <svg width={size} height={size} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
    <path d="M14 2H6a2 2 0 0 0-2 2v16a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V8z"/>
    <polyline points="14 2 14 8 20 8"/>
  </svg>
);

const IconRefresh = ({ size = 18 }) => (
  <svg width={size} height={size} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
    <polyline points="17 1 21 5 17 9"/>
    <path d="M3 11V9a4 4 0 0 1 4-4h14"/>
    <polyline points="7 23 3 19 7 15"/>
    <path d="M21 13v2a4 4 0 0 1-4 4H3"/>
  </svg>
);

const IconChevronLeft = () => (
  <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
    <polyline points="15 18 9 12 15 6"/>
  </svg>
);

const IconChevronRight = () => (
  <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
    <polyline points="9 18 15 12 9 6"/>
  </svg>
);

const IconClock = ({ size = 12 }) => (
  <svg width={size} height={size} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
    <circle cx="12" cy="12" r="10"/>
    <polyline points="12 6 12 12 16 14"/>
  </svg>
);

const IconTrend = () => (
  <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
    <polyline points="23 6 13.5 15.5 8.5 10.5 1 18"/>
    <polyline points="17 6 23 6 23 12"/>
  </svg>
);

// ─── Constants ────────────────────────────────────────────────────────────────

const PALETTE = {
  blue: '#406CDE',
  dark: '#111729',
  purple: '#BA6AA8',
  green: '#4D9468',
  bg: '#191E2A',
};

const MONTHS_FR = ['Jan','Fév','Mar','Avr','Mai','Jun','Jul','Aoû','Sep','Oct','Nov','Déc'];
const DAYS_FR = ['L','M','M','J','V','S','D'];

// ─── Helpers ──────────────────────────────────────────────────────────────────

function isSameDay(a, b) {
  return a.getFullYear() === b.getFullYear() &&
    a.getMonth() === b.getMonth() &&
    a.getDate() === b.getDate();
}

function getDaysInMonth(year, month) {
  return new Date(year, month + 1, 0).getDate();
}

function getMondayDay(date) {
  return (date.getDay() + 6) % 7;
}

function formatTime(dateStr) {
  if (!dateStr) return '';
  return new Date(dateStr).toLocaleTimeString('fr-FR', { hour: '2-digit', minute: '2-digit' });
}

// Build monthly candidate counts from createdAt
function buildMonthlyData(candidates) {
  const now = new Date();
  const counts = Array(6).fill(0);
  const labels = [];
  for (let i = 5; i >= 0; i--) {
    const d = new Date(now.getFullYear(), now.getMonth() - i, 1);
    labels.push(MONTHS_FR[d.getMonth()]);
  }
  candidates.forEach(c => {
    const d = new Date(c.createdAt);
    const monthsAgo = (now.getFullYear() - d.getFullYear()) * 12 + (now.getMonth() - d.getMonth());
    if (monthsAgo >= 0 && monthsAgo < 6) {
      counts[5 - monthsAgo]++;
    }
  });
  return { labels, counts };
}

// Build status distribution
function buildStatusData(candidates) {
  const map = {};
  candidates.forEach(c => {
    const s = c.status || 'Inconnu';
    map[s] = (map[s] || 0) + 1;
  });
  return Object.entries(map).map(([label, value]) => ({ label, value }));
}

// ─── Line Chart (SVG, no lib needed) ─────────────────────────────────────────

function LineChart({ labels, data, color, height = 120 }) {
  if (!data || data.length === 0) return null;
  const W = 420, H = height;
  const pad = { top: 12, right: 12, bottom: 28, left: 28 };
  const maxVal = Math.max(...data, 1);
  const pts = data.map((v, i) => {
    const x = pad.left + (i / (data.length - 1)) * (W - pad.left - pad.right);
    const y = pad.top + (1 - v / maxVal) * (H - pad.top - pad.bottom);
    return { x, y, v };
  });
  const line = pts.map((p, i) => `${i === 0 ? 'M' : 'L'}${p.x},${p.y}`).join(' ');
  const area = `${line} L${pts[pts.length-1].x},${H - pad.bottom} L${pts[0].x},${H - pad.bottom} Z`;

  return (
    <svg viewBox={`0 0 ${W} ${H}`} style={{ width: '100%', height }}>
      {/* Grid lines */}
      {[0, 0.25, 0.5, 0.75, 1].map((t, i) => {
        const y = pad.top + t * (H - pad.top - pad.bottom);
        return <line key={i} x1={pad.left} y1={y} x2={W - pad.right} y2={y} stroke="rgba(255,255,255,0.05)" strokeWidth="1"/>;
      })}

      {/* Area fill */}
      <defs>
        <linearGradient id={`grad-${color.replace('#','')}`} x1="0" y1="0" x2="0" y2="1">
          <stop offset="0%" stopColor={color} stopOpacity="0.3"/>
          <stop offset="100%" stopColor={color} stopOpacity="0"/>
        </linearGradient>
      </defs>
      <path d={area} fill={`url(#grad-${color.replace('#','')})`}/>

      {/* Line */}
      <path d={line} fill="none" stroke={color} strokeWidth="2" strokeLinejoin="round" strokeLinecap="round"/>

      {/* Points */}
      {pts.map((p, i) => (
        <g key={i}>
          <circle cx={p.x} cy={p.y} r="4" fill={PALETTE.bg} stroke={color} strokeWidth="2"/>
        </g>
      ))}

      {/* X labels */}
      {labels.map((l, i) => {
        const x = pad.left + (i / (labels.length - 1)) * (W - pad.left - pad.right);
        return (
          <text key={i} x={x} y={H - 6} textAnchor="middle" fontSize="10" fill="rgba(255,255,255,0.35)" fontFamily="inherit">
            {l}
          </text>
        );
      })}

      {/* Y max */}
      <text x={pad.left - 4} y={pad.top + 4} textAnchor="end" fontSize="10" fill="rgba(255,255,255,0.35)" fontFamily="inherit">
        {maxVal}
      </text>
    </svg>
  );
}

// ─── Donut Chart ──────────────────────────────────────────────────────────────

const STATUS_COLORS = ['#406CDE', '#4D9468', '#BA6AA8', '#F0A500', '#E05C5C', '#5CC8E0'];

function DonutChart({ segments }) {
  const total = segments.reduce((s, d) => s + d.value, 0);
  if (total === 0) return <div style={{ textAlign: 'center', color: 'rgba(255,255,255,0.3)', fontSize: 13, padding: 20 }}>Aucune donnée</div>;

  const R = 60, cx = 80, cy = 80, stroke = 36;
  const circumference = 2 * Math.PI * R;
  let offset = 0;
  const arcs = segments.map((seg, i) => {
    const pct = seg.value / total;
    const dash = pct * circumference;
    const gap = circumference - dash;
    const arc = { ...seg, dash, gap, offset: circumference * (1 - offset) - dash, color: STATUS_COLORS[i % STATUS_COLORS.length], pct };
    offset += pct;
    return arc;
  });

  return (
    <div style={{ display: 'flex', alignItems: 'center', gap: 20 }}>
      <svg viewBox="0 0 160 160" width="130" height="130" style={{ flexShrink: 0 }}>
        {arcs.map((arc, i) => (
          <circle
            key={i}
            cx={cx} cy={cy} r={R}
            fill="none"
            stroke={arc.color}
            strokeWidth={stroke}
            strokeDasharray={`${arc.dash} ${arc.gap}`}
            strokeDashoffset={arc.offset}
            transform={`rotate(-90 ${cx} ${cy})`}
            style={{ transition: 'stroke-dasharray 0.5s ease' }}
          />
        ))}
        <text x={cx} y={cy - 6} textAnchor="middle" fontSize="22" fontWeight="700" fill="white" fontFamily="inherit">{total}</text>
        <text x={cx} y={cy + 12} textAnchor="middle" fontSize="10" fill="rgba(255,255,255,0.4)" fontFamily="inherit">profils</text>
      </svg>
      <div style={{ display: 'flex', flexDirection: 'column', gap: 8, flex: 1, minWidth: 0 }}>
        {arcs.map((arc, i) => (
          <div key={i} style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
            <span style={{ width: 8, height: 8, borderRadius: 2, background: arc.color, flexShrink: 0 }}/>
            <span style={{ fontSize: 12, color: 'rgba(255,255,255,0.6)', flex: 1, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{arc.label}</span>
            <span style={{ fontSize: 12, fontWeight: 600, color: 'white' }}>{arc.value}</span>
            <span style={{ fontSize: 11, color: 'rgba(255,255,255,0.3)', minWidth: 32, textAlign: 'right' }}>{Math.round(arc.pct * 100)}%</span>
          </div>
        ))}
      </div>
    </div>
  );
}

// ─── Bar Chart ────────────────────────────────────────────────────────────────

function BarChart({ labels, data, color, height = 100 }) {
  if (!data || data.length === 0) return null;
  const maxVal = Math.max(...data, 1);
  return (
    <div style={{ display: 'flex', alignItems: 'flex-end', gap: 6, height, paddingTop: 8 }}>
      {data.map((v, i) => (
        <div key={i} style={{ flex: 1, display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 4, height: '100%', justifyContent: 'flex-end' }}>
          <span style={{ fontSize: 10, color: 'rgba(255,255,255,0.4)' }}>{v}</span>
          <div style={{
            width: '100%',
            height: `${Math.max((v / maxVal) * (height - 24), v > 0 ? 4 : 0)}px`,
            borderRadius: '4px 4px 0 0',
            background: `linear-gradient(180deg, ${color} 0%, ${color}88 100%)`,
            transition: 'height 0.5s ease',
            minHeight: v > 0 ? 4 : 0,
          }}/>
          <span style={{ fontSize: 10, color: 'rgba(255,255,255,0.35)', marginTop: 2 }}>{labels[i]}</span>
        </div>
      ))}
    </div>
  );
}

