// ─── Mini Agenda ─────────────────────────────────────────────────────────────

function MiniAgenda() {
  const [events, setEvents] = useState([]);
  const [loading, setLoading] = useState(false);
  const [connected, setConnected] = useState(false);
  const [currentDate, setCurrentDate] = useState(new Date());
  const today = new Date();

  const year = currentDate.getFullYear();
  const month = currentDate.getMonth();
  const daysInMonth = getDaysInMonth(year, month);
  const firstDay = getMondayDay(new Date(year, month, 1));

  const loadEvents = useCallback(async () => {
    if (!keycloak?.token) return;
    setLoading(true);
    try {
      const timeMin = new Date(year, month, 1).toISOString();
      const timeMax = new Date(year, month + 1, 0, 23, 59, 59).toISOString();
      const res = await fetch(
        `https://www.googleapis.com/calendar/v3/calendars/primary/events?timeMin=${timeMin}&timeMax=${timeMax}&singleEvents=true&orderBy=startTime&maxResults=50`,
        { headers: { Authorization: `Bearer ${keycloak.token}` } }
      );
      if (res.ok) {
        const data = await res.json();
        setEvents(data.items || []);
        setConnected(true);
      }
    } catch (_) {}
    setLoading(false);
  }, [year, month]);

  useEffect(() => { loadEvents(); }, [loadEvents]);

  const getEventsForDay = (day) => {
    const d = new Date(year, month, day);
    return events.filter(ev => {
      const start = new Date(ev.start?.dateTime || ev.start?.date);
      return isSameDay(start, d);
    });
  };

  // Upcoming events (today + future in current month)
  const upcomingEvents = events
    .filter(ev => {
      const start = new Date(ev.start?.dateTime || ev.start?.date);
      return start >= new Date(today.setHours(0,0,0,0));
    })
    .slice(0, 4);

  const totalCells = Math.ceil((firstDay + daysInMonth) / 7) * 7;

  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: 0, height: '100%' }}>
      {/* Month nav */}
      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 16 }}>
        <span style={{ fontSize: 13, fontWeight: 600, color: 'white' }}>
          {MONTHS_FR[month]} {year}
        </span>
        <div style={{ display: 'flex', gap: 4 }}>
          {[
            { icon: <IconChevronLeft/>, onClick: () => setCurrentDate(new Date(year, month - 1, 1)) },
            { icon: <IconChevronRight/>, onClick: () => setCurrentDate(new Date(year, month + 1, 1)) },
          ].map(({ icon, onClick }, i) => (
            <button key={i} onClick={onClick} style={{
              width: 26, height: 26, borderRadius: 6, border: '1px solid rgba(255,255,255,0.1)',
              background: 'rgba(255,255,255,0.05)', color: 'rgba(255,255,255,0.6)',
              display: 'flex', alignItems: 'center', justifyContent: 'center',
              cursor: 'pointer',
            }}>{icon}</button>
          ))}
        </div>
      </div>

      {/* Day headers */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(7, 1fr)', marginBottom: 6 }}>
        {DAYS_FR.map((d, i) => (
          <div key={i} style={{ textAlign: 'center', fontSize: 10, color: 'rgba(255,255,255,0.3)', fontWeight: 600, padding: '2px 0' }}>{d}</div>
        ))}
      </div>

      {/* Calendar grid */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(7, 1fr)', gap: 2, marginBottom: 16 }}>
        {Array.from({ length: totalCells }).map((_, i) => {
          const day = i - firstDay + 1;
          const valid = day >= 1 && day <= daysInMonth;
          const isToday = valid && isSameDay(new Date(year, month, day), new Date());
          const hasEvents = valid && getEventsForDay(day).length > 0;
          const isPast = valid && new Date(year, month, day) < new Date(new Date().setHours(0,0,0,0));

          return (
            <div key={i} style={{
              height: 28, display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center',
              borderRadius: 6,
              background: isToday ? PALETTE.blue : 'transparent',
              position: 'relative',
            }}>
              <span style={{
                fontSize: 11, fontWeight: isToday ? 700 : 400,
                color: isToday ? 'white' : valid ? (isPast ? 'rgba(255,255,255,0.2)' : 'rgba(255,255,255,0.7)') : 'transparent',
              }}>
                {valid ? day : ''}
              </span>
              {hasEvents && !isToday && (
                <div style={{ width: 4, height: 4, borderRadius: '50%', background: PALETTE.purple, position: 'absolute', bottom: 2 }}/>
              )}
            </div>
          );
        })}
      </div>

      {/* Upcoming events */}
      <div style={{ flex: 1 }}>
        <p style={{ fontSize: 11, color: 'rgba(255,255,255,0.3)', margin: '0 0 10px', textTransform: 'uppercase', letterSpacing: '0.06em', fontWeight: 600 }}>
          À venir
        </p>
        {loading && (
          <div style={{ fontSize: 12, color: 'rgba(255,255,255,0.3)', textAlign: 'center', padding: '12px 0' }}>Chargement...</div>
        )}
        {!loading && !connected && (
          <div style={{ fontSize: 12, color: 'rgba(255,255,255,0.25)', textAlign: 'center', padding: '12px 0' }}>
            Connectez Google Calendar
          </div>
        )}
        {!loading && connected && upcomingEvents.length === 0 && (
          <div style={{ fontSize: 12, color: 'rgba(255,255,255,0.25)', textAlign: 'center', padding: '12px 0' }}>
            Aucun événement à venir
          </div>
        )}
        <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
          {upcomingEvents.map((ev, i) => {
            const start = ev.start?.dateTime || ev.start?.date;
            const d = new Date(start);
            const colors = [PALETTE.blue, PALETTE.purple, PALETTE.green, '#F0A500'];
            const c = colors[i % colors.length];
            return (
              <div key={ev.id} style={{
                display: 'flex', gap: 10, alignItems: 'center',
                padding: '8px 10px',
                background: 'rgba(255,255,255,0.04)',
                borderRadius: 10,
                borderLeft: `3px solid ${c}`,
              }}>
                <div style={{ flexShrink: 0, textAlign: 'center', minWidth: 28 }}>
                  <div style={{ fontSize: 15, fontWeight: 700, color: c, lineHeight: 1 }}>{d.getDate()}</div>
                  <div style={{ fontSize: 9, color: 'rgba(255,255,255,0.3)', textTransform: 'uppercase' }}>{MONTHS_FR[d.getMonth()]}</div>
                </div>
                <div style={{ flex: 1, minWidth: 0 }}>
                  <div style={{ fontSize: 12, fontWeight: 600, color: 'rgba(255,255,255,0.85)', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
                    {ev.summary || '(Sans titre)'}
                  </div>
                  {ev.start?.dateTime && (
                    <div style={{ fontSize: 11, color: 'rgba(255,255,255,0.35)', display: 'flex', alignItems: 'center', gap: 3, marginTop: 2 }}>
                      <IconClock size={10}/>
                      {formatTime(start)}
                    </div>
                  )}
                </div>
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
}

// ─── Recent Activity ──────────────────────────────────────────────────────────

function RecentActivity({ candidates }) {
  const recent = [...candidates]
    .sort((a, b) => new Date(b.createdAt) - new Date(a.createdAt))
    .slice(0, 5);

  if (recent.length === 0) return (
    <div style={{ textAlign: 'center', padding: '24px 0', color: 'rgba(255,255,255,0.25)', fontSize: 13 }}>
      Importez des profils pour voir l'activité
    </div>
  );

  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: 6 }}>
      {recent.map((c, i) => {
        const d = new Date(c.createdAt);
        const ago = Math.floor((Date.now() - d) / 86400000);
        const agoStr = ago === 0 ? "Aujourd'hui" : ago === 1 ? 'Hier' : `Il y a ${ago}j`;
        const initials = ((c.firstName?.[0] || '') + (c.lastName?.[0] || '')).toUpperCase() || '?';
        const colors = [PALETTE.blue, PALETTE.purple, PALETTE.green, '#F0A500', '#E05C5C'];
        const col = colors[i % colors.length];
        return (
          <div key={c.id || i} style={{
            display: 'flex', alignItems: 'center', gap: 12,
            padding: '10px 12px',
            borderRadius: 10,
            background: 'rgba(255,255,255,0.03)',
            transition: 'background 0.2s',
          }}
            onMouseEnter={e => e.currentTarget.style.background = 'rgba(255,255,255,0.07)'}
            onMouseLeave={e => e.currentTarget.style.background = 'rgba(255,255,255,0.03)'}
          >
            <div style={{
              width: 34, height: 34, borderRadius: '50%', flexShrink: 0,
              background: `${col}22`,
              display: 'flex', alignItems: 'center', justifyContent: 'center',
              fontSize: 12, fontWeight: 700, color: col,
            }}>{initials}</div>
            <div style={{ flex: 1, minWidth: 0 }}>
              <div style={{ fontSize: 13, fontWeight: 600, color: 'rgba(255,255,255,0.85)', overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
                {c.firstName} {c.lastName}
              </div>
              <div style={{ fontSize: 11, color: 'rgba(255,255,255,0.35)' }}>{c.title || c.poste || 'Profil candidat'}</div>
            </div>
            <div style={{ flexShrink: 0, textAlign: 'right' }}>
              <span style={{ fontSize: 11, color: 'rgba(255,255,255,0.3)' }}>{agoStr}</span>
            </div>
            {c.status && (
              <span style={{
                fontSize: 10, padding: '3px 8px', borderRadius: 20,
                background: c.status.toLowerCase().includes('actif') || c.status.toLowerCase().includes('retenu') ? `${PALETTE.green}22` :
                  c.status.toLowerCase().includes('rejet') ? 'rgba(224,92,92,0.15)' : 'rgba(64,108,222,0.15)',
                color: c.status.toLowerCase().includes('actif') || c.status.toLowerCase().includes('retenu') ? PALETTE.green :
                  c.status.toLowerCase().includes('rejet') ? '#E05C5C' : PALETTE.blue,
                fontWeight: 600, marginLeft: 4,
              }}>{c.status}</span>
            )}
          </div>
        );
      })}
    </div>
  );
}

// ─── Card wrapper ─────────────────────────────────────────────────────────────

function Card({ title, subtitle, children, style = {}, action }) {
  return (
    <div style={{
      background: PALETTE.dark,
      border: '1px solid rgba(255,255,255,0.07)',
      borderRadius: 16,
      padding: '22px 24px',
      display: 'flex',
      flexDirection: 'column',
      ...style,
    }}>
      {(title || action) && (
        <div style={{ display: 'flex', alignItems: 'flex-start', justifyContent: 'space-between', marginBottom: 16 }}>
          <div>
            {title && <h3 style={{ margin: 0, fontSize: 14, fontWeight: 600, color: 'rgba(255,255,255,0.85)' }}>{title}</h3>}
            {subtitle && <p style={{ margin: '3px 0 0', fontSize: 12, color: 'rgba(255,255,255,0.35)' }}>{subtitle}</p>}
          </div>
          {action}
        </div>
      )}
      {children}
    </div>
  );
}

// ─── Main Dashboard ───────────────────────────────────────────────────────────

export default function Dashboard() {
  const [candidates, setCandidates] = useState([]);
  const [templates, setTemplates] = useState([]);
  const [transformations, setTransformations] = useState([]);
  const [loading, setLoading] = useState(true);
  const navigate = useNavigate();

  useEffect(() => {
    setLoading(true);
    Promise.all([
      api.get('/candidates').catch(() => ({ data: [] })),
      api.get('/templates').catch(() => ({ data: [] })),
      api.get('/transformations').catch(() => ({ data: [] })),
    ]).then(([cands, tmpls, trans]) => {
      setCandidates(cands.data || []);
      setTemplates(tmpls.data || []);
      setTransformations(trans.data || []);
      setLoading(false);
    });
  }, []);

  const { labels: monthLabels, counts: monthCounts } = buildMonthlyData(candidates);
  const statusData = buildStatusData(candidates);

  // Templates used per category/name (take first 6)
  const templateBarLabels = templates.slice(0, 6).map(t => (t.name || t.titre || 'T').slice(0, 6));
  const templateBarData = templates.slice(0, 6).map(t => t.usageCount || t.used || 0);

  // Transformation monthly
  const { counts: transCounts } = buildMonthlyData(transformations.map(t => ({ ...t, createdAt: t.createdAt || t.date })));

  const thisMonthCandidates = monthCounts[5];
  const lastMonthCandidates = monthCounts[4];
  const candidateTrend = lastMonthCandidates > 0 ? Math.round(((thisMonthCandidates - lastMonthCandidates) / lastMonthCandidates) * 100) : null;

  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: 20, fontFamily: 'inherit', color: 'white' }}>

      {/* ── Top bar ── */}
      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
        <div>
          <h1 style={{ margin: 0, fontSize: 22, fontWeight: 700, color: 'white' }}>
            Tableau de bord
          </h1>
          <p style={{ margin: '3px 0 0', fontSize: 13, color: 'rgba(255,255,255,0.4)' }}>
            {new Date().toLocaleDateString('fr-FR', { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' })}
          </p>
        </div>
        <div style={{ display: 'flex', gap: 10 }}>
          <button
            onClick={() => navigate('/profiles')}
            style={{
              display: 'inline-flex', alignItems: 'center', gap: 6,
              padding: '9px 18px', borderRadius: 999,
              border: '1px solid rgba(255,255,255,0.12)',
              background: 'rgba(255,255,255,0.06)',
              color: 'rgba(255,255,255,0.8)',
              fontSize: 13, fontWeight: 500, cursor: 'pointer',
              transition: 'background 0.2s',
            }}
            onMouseEnter={e => e.currentTarget.style.background = 'rgba(255,255,255,0.1)'}
            onMouseLeave={e => e.currentTarget.style.background = 'rgba(255,255,255,0.06)'}
          >
            ↑ Importer CV
          </button>
          <button
            onClick={() => navigate('/profiles')}
            style={{
              display: 'inline-flex', alignItems: 'center', gap: 6,
              padding: '9px 18px', borderRadius: 999,
              border: 'none',
              background: PALETTE.blue,
              color: 'white',
              fontSize: 13, fontWeight: 600, cursor: 'pointer',
              boxShadow: `0 4px 18px ${PALETTE.blue}55`,
              transition: 'opacity 0.2s, transform 0.2s',
            }}
            onMouseEnter={e => { e.currentTarget.style.opacity = '0.9'; e.currentTarget.style.transform = 'translateY(-1px)'; }}
            onMouseLeave={e => { e.currentTarget.style.opacity = '1'; e.currentTarget.style.transform = 'translateY(0)'; }}
          >
            + Nouveau profil
          </button>
        </div>
      </div>

      {/* ── Stat cards ── */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: 14 }}>
        <StatCard
          label="Profils actifs"
          value={candidates.length}
          sub={`ce mois : ${thisMonthCandidates}`}
          trend={candidateTrend !== null ? candidateTrend : undefined}
          icon={<IconUsers />}
          color={PALETTE.blue}
          onClick={() => navigate('/profiles')}
        />
        <StatCard
          label="Templates"
          value={templates.length}
          sub="Prêts à l'emploi"
          icon={<IconFile />}
          color={PALETTE.purple}
          onClick={() => navigate('/templates')}
        />
        <StatCard
          label="CV transformés"
          value={transformations.length}
          sub="Total"
          icon={<IconRefresh />}
          color={PALETTE.green}
          onClick={() => navigate('/transformation')}
        />
      </div>

      {/* ── Main grid (2 cols) ── */}
      <div style={{ display: 'grid', gridTemplateColumns: '1fr 300px', gap: 14, alignItems: 'start' }}>

        {/* Left column */}
        <div style={{ display: 'flex', flexDirection: 'column', gap: 14 }}>

          {/* Candidates trend */}
          <Card
            title="Candidats importés"
            subtitle="Évolution sur 6 mois"
            action={
              <span style={{ fontSize: 11, padding: '3px 10px', borderRadius: 20, background: `${PALETTE.blue}22`, color: PALETTE.blue, fontWeight: 600 }}>
                6 mois
              </span>
            }
          >
            <LineChart labels={monthLabels} data={monthCounts} color={PALETTE.blue} height={130} />
          </Card>

          {/* 2-col row: donut + bar */}
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 14 }}>
            <Card title="Statuts candidats" subtitle="Répartition actuelle">
              <DonutChart segments={statusData.length > 0 ? statusData : [{ label: 'Aucun profil', value: 0 }]} />
            </Card>

            <Card title="Templates" subtitle="Utilisation par template">
              {templateBarLabels.length > 0 ? (
                <BarChart labels={templateBarLabels} data={templateBarData} color={PALETTE.purple} height={110} />
