          {/* CV transformations trend */}
          <Card
            title="Transformations de CV"
            subtitle="Volume mensuel"
            action={
              <span style={{ fontSize: 11, padding: '3px 10px', borderRadius: 20, background: `${PALETTE.green}22`, color: PALETTE.green, fontWeight: 600 }}>
                6 mois
              </span>
            }
          >
            <LineChart labels={monthLabels} data={transCounts} color={PALETTE.green} height={110} />
          </Card>

          {/* Recent activity */}
          <Card title="Activité récente" subtitle="Derniers profils ajoutés">
            {loading ? (
              <div style={{ textAlign: 'center', padding: '20px 0', color: 'rgba(255,255,255,0.3)', fontSize: 13 }}>Chargement...</div>
            ) : (
              <RecentActivity candidates={candidates} />
            )}
          </Card>
        </div>

        {/* Right column — Mini Agenda */}
        <Card
          title="Agenda"
          subtitle="Google Calendar"
          style={{ position: 'sticky', top: 20, minHeight: 560 }}
        >
          <MiniAgenda />
        </Card>
      </div>

      {/* ── Quick actions ── */}
      <Card title="Actions rapides">
        <div style={{ display: 'flex', flexWrap: 'wrap', gap: 10 }}>
          {[
            { label: '+ Importer un CV', path: '/profiles', color: PALETTE.blue },
            { label: 'Voir les templates', path: '/templates', color: PALETTE.purple },
            { label: 'Transformer un CV', path: '/transformation', color: PALETTE.green },
          ].map(({ label, path, color }) => (
            <button
              key={label}
              onClick={() => navigate(path)}
              style={{
                padding: '10px 20px', borderRadius: 999,
                border: `1px solid ${color}44`,
                background: `${color}15`,
                color,
                fontSize: 13, fontWeight: 600,
                cursor: 'pointer', transition: 'background 0.2s, transform 0.2s',
              }}
              onMouseEnter={e => { e.currentTarget.style.background = `${color}28`; e.currentTarget.style.transform = 'translateY(-1px)'; }}
              onMouseLeave={e => { e.currentTarget.style.background = `${color}15`; e.currentTarget.style.transform = 'translateY(0)'; }}
            >
              {label}
            </button>
          ))}
        </div>
      </Card>
    </div>
  );
}
